extension NativeAppAction: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeNativeAppAction: FfiConverterRustBuffer {
    typealias SwiftType = NativeAppAction

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> NativeAppAction {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        case 1: return .getState

        case 2: return .tick

        case 3: return .connectVpn

        case 4: return .disconnectVpn

        case 5: return .installCli

        case 6: return .uninstallCli

        case 7: return .installSystemService

        case 8: return .uninstallSystemService

        case 9: return .enableSystemService

        case 10: return .disableSystemService

        case 11: return .addNetwork(name: try FfiConverterString.read(from: &buf)
        )

